import{_ as a,l as e,k as i,ad as o}from"./chunks/framework.CZ3uBn-2.js";const m=JSON.parse('{"title":"01 静力学分析思维框架","description":"","frontmatter":{"cate":["相互作用力","重力、弹力与摩擦力"],"type":1},"headers":[],"relativePath":"gaozhong/物理/合集/01 必修一/03 相互作用力/01 基础课-静力学分析思维框架.md","filePath":"gaozhong/物理/合集/01 必修一/03 相互作用力/01 基础课-静力学分析思维框架.md","lastUpdated":1718437853000}'),s={name:"gaozhong/物理/合集/01 必修一/03 相互作用力/01 基础课-静力学分析思维框架.md"},t=o('<h1 id="_01-静力学分析思维框架" tabindex="-1">01 静力学分析思维框架 <a class="header-anchor" href="#_01-静力学分析思维框架" aria-label="Permalink to &quot;01 静力学分析思维框架&quot;">​</a></h1><p>要学的东西很多。</p><p>重力和弹力和摩擦力的性质、力的合成与分解、平行四边形定则、三角形定则、胡可定律、受力分析、正交分解、晾衣杆模型、整体隔离法……</p><h2 id="学习本章节目标" tabindex="-1">学习本章节目标 <a class="header-anchor" href="#学习本章节目标" aria-label="Permalink to &quot;学习本章节目标&quot;">​</a></h2><ol><li>了解静力学分析题目背后的大思路，大步骤</li><li>了解力学部分每块内容有啥用，有啥联系</li></ol><h2 id="什么是力学分析" tabindex="-1">什么是力学分析 <a class="header-anchor" href="#什么是力学分析" aria-label="Permalink to &quot;什么是力学分析&quot;">​</a></h2><p>力学分为静力学分析和动力学分析。本章节主要讲静力学分析。</p><h3 id="静力学分析" tabindex="-1">静力学分析 <a class="header-anchor" href="#静力学分析" aria-label="Permalink to &quot;静力学分析&quot;">​</a></h3><p>题目特征：已知物体受力平衡，让你求某个力。</p><p>解题核心：利用合力为 0 进行分析。</p><h4 id="力的性质与受力分析" tabindex="-1">力的性质与受力分析 <a class="header-anchor" href="#力的性质与受力分析" aria-label="Permalink to &quot;力的性质与受力分析&quot;">​</a></h4><p>大多数情况下我们不知道受力的个数、方向。</p><p>所以我们需要了解重力、弹力、摩擦力的性质，然后进行受力分析。</p><img src="https://my-course-public.oss-cn-shanghai.aliyuncs.com/public/assets/gaozhong_physics/physics_62.png"><h4 id="力的合成与分解" tabindex="-1">力的合成与分解 <a class="header-anchor" href="#力的合成与分解" aria-label="Permalink to &quot;力的合成与分解&quot;">​</a></h4><p>大多数情况下力是不共线的，所以需要进行力的合成与分解。</p><img src="https://my-course-public.oss-cn-shanghai.aliyuncs.com/public/assets/gaozhong_physics/physics_63.png"><h3 id="动力学分析" tabindex="-1">动力学分析 <a class="header-anchor" href="#动力学分析" aria-label="Permalink to &quot;动力学分析&quot;">​</a></h3><p>题目特征：物体合外力不为零。</p><p>解题核心：力和运动的关系。</p><h2 id="静力学分析思维框架" tabindex="-1">静力学分析思维框架 <a class="header-anchor" href="#静力学分析思维框架" aria-label="Permalink to &quot;静力学分析思维框架&quot;">​</a></h2><ol><li>受力分析</li><li>力的合成与分解</li><li>利用合力 =0 求某个力</li></ol><h2 id="实战训练" tabindex="-1">实战训练 <a class="header-anchor" href="#实战训练" aria-label="Permalink to &quot;实战训练&quot;">​</a></h2><p>需要专门练习的题型：</p><ol><li>静态平衡问题</li><li>动态平衡问题</li></ol><img src="https://my-course-public.oss-cn-shanghai.aliyuncs.com/public/assets/gaozhong_physics/physics_64.png">',26),l=[t];function h(r,c,n,p,_,d){return i(),e("div",null,l)}const b=a(s,[["render",h]]);export{m as __pageData,b as default};
